5	// ── WHY THIS CLASS ───────────────────────────────────────────────────────────
6	// Thrown when a multi-seat hold cannot be fully satisfied — at least one of the
7	// requested seats is already HELD or BOOKED. It carries WHICH seats blocked the
8	// request so the caller can tell the user "A3 and A4 are taken" instead of a
9	// vague failure.
10	// 🎙️ "When even one requested seat is taken I reject the whole request and tell
11	//      the user exactly which seats blocked it — all-or-nothing, with a reason."
12	public class SeatsUnavailableException extends BookingException {
13	    private final List<String> conflictingSeats;
14	
15	    public SeatsUnavailableException(List<String> conflictingSeats) {
16	        super("Seats unavailable: " + conflictingSeats);
17	        this.conflictingSeats = List.copyOf(conflictingSeats);
18	    }
19	
20	    public List<String> getConflictingSeats() {
21	        return conflictingSeats;
22	    }
23	}
