3	import java.time.Instant;
4	import java.util.List;
5	
6	// ── WHY THIS CLASS ───────────────────────────────────────────────────────────
7	// A temporary claim on a set of seats. When a user picks seats, they get a
8	// SeatHold back: a hold id, the seats it covers, and an expiry timestamp 10 min
9	// out. They confirm with this hold id to pay. The sweeper uses expiresAt to find
10	// dead holds. It is a value object — once created it never changes; we replace
11	// it, never mutate it.
12	// 🎙️ "A hold is a temporary claim. It carries the seats, who owns it, and when it
13	//      dies. It is immutable — the seats' status lives on the seats, not here."
14	public record SeatHold(
15	        String holdId,
16	        String showtimeId,
17	        List<String> seatLabels,
18	        Instant expiresAt) {
19	
20	    // WHY: defensive copy so a caller cannot mutate the seat list after the hold
21	    //      is issued. A hold is a promise — it must not change under us.
22	    public SeatHold {
23	        seatLabels = List.copyOf(seatLabels);
24	    }
25	
26	    // WHY: time is passed IN, never read from the wall clock here. The sweeper and
27	    //      confirm() both ask "is this hold expired as of `now`?" using the SAME
28	    //      injected clock, so tests can fast-forward without sleeping.
29	    public boolean isExpired(Instant now) {
30	        return !now.isBefore(expiresAt);   // now >= expiresAt
31	    }
32	}
