// WHY: validate the request shape BEFORE mutating anything — empty list,
//      unknown seat labels, and DUPLICATE labels are all caller mistakes,
//      rejected with a clear error.
//
//      Duplicates matter for correctness, not just hygiene: phase 1 checks
//      isAvailable() per label, so a request like ["A1","A1"] passes the
//      check twice while A1 is still free. Phase 2 then calls hold() on A1
//      once (AVAILABLE -> HELD) and AGAIN on the same seat — the second call
//      throws from inside ShowSeat ("Cannot hold seat A1 in status HELD"),
//      which holdSeats does not anticipate. That leaves A1 stranded HELD with
//      NO hold recorded in the registry, so nothing can ever release it. We
//      forbid duplicates up front so phase 2 can never re-hold a seat.
private void validateSeatRequest(Showtime showtime, List<String> seatLabels) {
    if (seatLabels == null || seatLabels.isEmpty()) {
        throw new InvalidBookingException("Must request at least one seat");
    }
    Set<String> seen = new HashSet<>();
    for (String label : seatLabels) {
        if (showtime.getSeat(label) == null) {
            throw new InvalidBookingException(
                "Unknown seat " + label + " for showtime " + showtime.getShowtimeId());
        }
        if (!seen.add(label)) {
            throw new InvalidBookingException(
                "Duplicate seat " + label + " in request");
        }
    }
}

