11	// The thread-safe version of the booking service. It adds ONE thing to the clean
12	// core: a per-showtime lock. Everything else — the two-phase check-then-hold, the
13	// expiry guard, the sweeper — is inherited unchanged.
14	//
15	// The key idea: I lock PER SHOWTIME, not one global lock. Two users booking seats
16	// in two DIFFERENT showtimes never block each other; only users fighting over
17	// seats in the SAME showtime serialize. That is the natural unit of contention.
18	//
19	// 🎙️ "The thread-safe service is a subclass. I override the two lock hooks to
20	//      grab a per-showtime lock. The whole two-phase check-and-hold runs under
21	//      that lock, so two users who want the same seat can never both win."
22	public class ThreadSafeBookingService extends BookingService {
23	
24	    // showtime id -> its lock. ReentrantLock because a guarded method could call
25	    // another guarded method on the same thread; reentrancy lets it re-enter
26	    // instead of deadlocking on itself.
27	    private final Map<String, ReentrantLock> locks = new ConcurrentHashMap<>();
28	
29	    public ThreadSafeBookingService(Clock clock) {
30	        super(clock);
31	    }
32	
33	    public ThreadSafeBookingService(Clock clock, Duration holdDuration) {
34	        super(clock, holdDuration);
35	    }
36	
37	    // WHY: computeIfAbsent on a ConcurrentHashMap is itself atomic, so two threads
38	    //      that first touch the same showtime get the SAME lock object — there is
39	    //      no race that could hand out two different locks for one showtime.
40	    //      That is the "lock the map of locks" idea, done safely with CHM.
41	    @Override
42	    protected void gateLock(String showtimeId) {
43	        ReentrantLock lock = locks.computeIfAbsent(showtimeId, id -> new ReentrantLock());
44	        lock.lock();
45	    }
46	
47	    @Override
48	    protected void gateUnlock(String showtimeId) {
49	        // The lock for this showtime always exists by the time we unlock, because
50	        // gateLock created it. Held by THIS thread, so unlock() is safe.
51	        locks.get(showtimeId).unlock();
52	    }
53	}
